@page "/"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject ApplicationDbContext Db

<PageTitle>Dashboard — VetClinic</PageTitle>

<h1>Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4 mb-3">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@patientCount</p>
                <a href="patients" class="btn btn-light btn-sm">View All</a>
            </div>
        </div>
    </div>
    <div class="col-md-4 mb-3">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
                <a href="appointments" class="btn btn-light btn-sm">View Schedule</a>
            </div>
        </div>
    </div>
    <div class="col-md-4 mb-3">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
                <a href="billing" class="btn btn-light btn-sm">View Billing</a>
            </div>
        </div>
    </div>
</div>

<div class="row mt-4">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-sm">
                <thead><tr><th>Time</th><th>Patient</th><th>Reason</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
                    {
                        <tr>
                            <td>@apt.ScheduledAt.ToString("g")</td>
                            <td>@apt.Patient.Name</td>
                            <td>@apt.Reason</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Patients</h4>
        @if (recentPatients.Any())
        {
            <table class="table table-sm">
                <thead><tr><th>Name</th><th>Species</th><th>Owner</th></tr></thead>
                <tbody>
                    @foreach (var p in recentPatients)
                    {
                        <tr>
                            <td><a href="patients/@p.Id">@p.Name</a></td>
                            <td>@p.Species</td>
                            <td>@p.OwnerName</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No patients registered yet.</p>
        }
    </div>
</div>

@code {
    private int patientCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<Appointment> upcomingAppointments = new();
    private List<Patient> recentPatients = new();

    protected override async Task OnInitializedAsync()
    {
        patientCount = await Db.Patients.CountAsync();
        var today = DateTime.UtcNow.Date;
        todayAppointments = await Db.Appointments
            .CountAsync(a => a.ScheduledAt.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await Db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Unpaid || i.Status == InvoiceStatus.PartiallyPaid);
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.ScheduledAt >= DateTime.UtcNow && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledAt)
            .Take(5)
            .ToListAsync();
        recentPatients = await Db.Patients
            .OrderByDescending(p => p.CreatedAt)
            .Take(5)
            .ToListAsync();
    }
}

