@page "/patients"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patients — VetClinic</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by name, species, or owner..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="FilterPatients" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="() => showForm = !showForm">
            @(showForm ? "Cancel" : "Add Patient")
        </button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Register New Patient</h5>
            <EditForm Model="newPatient" OnValidSubmit="AddPatient" FormName="addPatient">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="newPatient.Name" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="newPatient.Species" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="newPatient.Breed" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="newPatient.DateOfBirth" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Owner Name</label>
                        <InputText class="form-control" @bind-Value="newPatient.OwnerName" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Owner Phone</label>
                        <InputText class="form-control" @bind-Value="newPatient.OwnerPhone" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Save Patient</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-striped table-hover">
    <thead>
        <tr>
            <th>Name</th>
            <th>Species</th>
            <th>Breed</th>
            <th>Owner</th>
            <th>Phone</th>
            <th>Registered</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var patient in filteredPatients)
        {
            <tr style="cursor:pointer" @onclick="() => Nav.NavigateTo($&quot;patients/{patient.Id}&quot;)">
                <td>@patient.Name</td>
                <td>@patient.Species</td>
                <td>@patient.Breed</td>
                <td>@patient.OwnerName</td>
                <td>@patient.OwnerPhone</td>
                <td>@patient.CreatedAt.ToString("d")</td>
            </tr>
        }
    </tbody>
</table>

@if (!filteredPatients.Any())
{
    <p class="text-muted">No patients found.</p>
}

@code {
    private List<Patient> patients = new();
    private List<Patient> filteredPatients = new();
    private string searchTerm = "";
    private bool showForm;
    private Patient newPatient = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadPatients();
    }

    private async Task LoadPatients()
    {
        patients = await Db.Patients.OrderByDescending(p => p.CreatedAt).ToListAsync();
        FilterPatients();
    }

    private void FilterPatients()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            filteredPatients = patients;
        }
        else
        {
            var term = searchTerm.ToLower();
            filteredPatients = patients.Where(p =>
                p.Name.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Species.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.OwnerName.Contains(term, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private async Task AddPatient()
    {
        newPatient.CreatedAt = DateTime.UtcNow;
        Db.Patients.Add(newPatient);
        await Db.SaveChangesAsync();
        newPatient = new();
        showForm = false;
        await LoadPatients();
    }
}

@page "/patients/{Id:int}"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patient Detail — VetClinic</PageTitle>

@if (patient == null)
{
    <p>Loading...</p>
}
else
{
    <h1>@patient.Name</h1>
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="patients">Patients</a></li>
            <li class="breadcrumb-item active">@patient.Name</li>
        </ol>
    </nav>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Patient Information</h5>
            <EditForm Model="patient" OnValidSubmit="UpdatePatient" FormName="editPatient">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="patient.Name" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="patient.Species" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="patient.Breed" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="patient.DateOfBirth" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Owner Name</label>
                        <InputText class="form-control" @bind-Value="patient.OwnerName" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Owner Phone</label>
                        <InputText class="form-control" @bind-Value="patient.OwnerPhone" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary">Update Patient</button>
                @if (saveMessage != null)
                {
                    <span class="text-success ms-2">@saveMessage</span>
                }
            </EditForm>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Add Treatment Note</h5>
            <EditForm Model="newNote" OnValidSubmit="AddNote" FormName="addNote">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
                <div class="row">
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Diagnosis</label>
                        <InputText class="form-control" @bind-Value="newNote.Diagnosis" />
                    </div>
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="newNote.Description" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Medication</label>
                        <InputText class="form-control" @bind-Value="newNote.Medication" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Cost ($)</label>
                        <InputNumber class="form-control" @bind-Value="newNote.Cost" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Staff Name</label>
                        <InputText class="form-control" @bind-Value="newNote.StaffName" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Add Note</button>
            </EditForm>
        </div>
    </div>

    <h4>Medical History</h4>
    @if (patient.TreatmentNotes.Any())
    {
        <div class="list-group mb-4">
            @foreach (var note in patient.TreatmentNotes.OrderByDescending(n => n.Date))
            {
                <div class="list-group-item">
                    <div class="d-flex justify-content-between">
                        <h6 class="mb-1">@note.Diagnosis</h6>
                        <small class="text-muted">@note.Date.ToString("g")</small>
                    </div>
                    <p class="mb-1">@note.Description</p>
                    <small>
                        @if (!string.IsNullOrEmpty(note.Medication))
                        {
                            <span class="badge bg-info me-2">Rx: @note.Medication</span>
                        }
                        @if (note.Cost > 0)
                        {
                            <span class="badge bg-secondary me-2">$@note.Cost.ToString("F2")</span>
                        }
                        @if (!string.IsNullOrEmpty(note.StaffName))
                        {
                            <span>By: @note.StaffName</span>
                        }
                    </small>
                </div>
            }
        </div>
    }
    else
    {
        <p class="text-muted">No treatment notes yet.</p>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Patient? patient;
    private TreatmentNote newNote = new();
    private string? saveMessage;

    protected override async Task OnInitializedAsync()
    {
        patient = await Db.Patients
            .Include(p => p.TreatmentNotes)
            .FirstOrDefaultAsync(p => p.Id == Id);
    }

    private async Task UpdatePatient()
    {
        await Db.SaveChangesAsync();
        saveMessage = "Saved!";
        await Task.Delay(2000);
        saveMessage = null;
    }

    private async Task AddNote()
    {
        newNote.PatientId = Id;
        newNote.Date = DateTime.UtcNow;
        Db.TreatmentNotes.Add(newNote);
        await Db.SaveChangesAsync();
        patient!.TreatmentNotes.Add(newNote);
        newNote = new();
    }
}

@page "/appointments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject ApplicationDbContext Db

<PageTitle>Appointments — VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Week of:</label>
        <input type="date" class="form-control" @bind="weekStart" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-outline-secondary me-2" @onclick="PreviousWeek">← Prev</button>
        <button class="btn btn-outline-secondary me-2" @onclick="() => { weekStart = DateOnly.FromDateTime(DateTime.Today); LoadAppointments(); }">Today</button>
        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next →</button>
    </div>
    <div class="col-md-4 text-end d-flex align-items-end justify-content-end">
        <button class="btn btn-primary" @onclick="() => showForm = !showForm">
            @(showForm ? "Cancel" : "New Appointment")
        </button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Schedule Appointment</h5>
            <EditForm Model="newAppointment" OnValidSubmit="CreateAppointment" FormName="newAppointment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="newAppointment.PatientId">
                            <option value="0">-- Select Patient --</option>
                            @foreach (var p in patients)
                            {
                                <option value="@p.Id">@p.Name (@p.Species)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="newAppointment.ScheduledAt" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="newAppointment.DurationMinutes" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
                    </div>
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Staff Name</label>
                        <InputText class="form-control" @bind-Value="newAppointment.StaffName" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Schedule</button>
                @if (formError != null)
                {
                    <span class="text-danger ms-2">@formError</span>
                }
            </EditForm>
        </div>
    </div>
}

@if (rescheduleTarget != null)
{
    <div class="card mb-4 border-warning">
        <div class="card-body">
            <h5 class="card-title">Reschedule: @rescheduleTarget.Patient.Name — @rescheduleTarget.Reason</h5>
            <div class="row">
                <div class="col-md-4 mb-2">
                    <label class="form-label">New Date & Time</label>
                    <input type="datetime-local" class="form-control" @bind="rescheduleDate" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <button class="btn btn-warning me-2" @onclick="ConfirmReschedule">Confirm</button>
                    <button class="btn btn-secondary" @onclick="() => rescheduleTarget = null">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th>Time</th>
                @for (int i = 0; i < 7; i++)
                {
                    var day = weekStart.AddDays(i);
                    <th>@day.ToString("ddd M/d")</th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-nowrap"><strong>@($"{hour}:00")</strong></td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotStart = day.ToDateTime(new TimeOnly(hour, 0));
                        var slotEnd = slotStart.AddHours(1);
                        var slotAppointments = appointments.Where(a =>
                            a.ScheduledAt >= slotStart && a.ScheduledAt < slotEnd).ToList();

                        <td>
                            @foreach (var apt in slotAppointments)
                            {
                                var badgeClass = apt.Status switch
                                {
                                    AppointmentStatus.Scheduled => "bg-primary",
                                    AppointmentStatus.Completed => "bg-success",
                                    AppointmentStatus.Cancelled => "bg-danger",
                                    _ => "bg-secondary"
                                };
                                <div class="mb-1">
                                    <span class="badge @badgeClass">@apt.Patient.Name</span>
                                    <small class="d-block">@apt.Reason</small>
                                    @if (apt.Status == AppointmentStatus.Scheduled)
                                    {
                                        <button class="btn btn-outline-warning btn-sm py-0 px-1 me-1" @onclick="() => StartReschedule(apt)">Reschedule</button>
                                        <button class="btn btn-outline-danger btn-sm py-0 px-1" @onclick="() => CancelAppointment(apt)">Cancel</button>
                                    }
                                </div>
                            }
                            @if (!slotAppointments.Any())
                            {
                                <span class="text-muted small">Available</span>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateOnly weekStart = DateOnly.FromDateTime(DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday));
    private List<Appointment> appointments = new();
    private List<Patient> patients = new();
    private Appointment newAppointment = new() { DurationMinutes = 30 };
    private bool showForm;
    private string? formError;
    private Appointment? rescheduleTarget;
    private DateTime rescheduleDate;

    protected override async Task OnInitializedAsync()
    {
        patients = await Db.Patients.OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var start = weekStart.ToDateTime(TimeOnly.MinValue);
        var end = start.AddDays(7);
        appointments = await Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.ScheduledAt >= start && a.ScheduledAt < end)
            .ToListAsync();
    }

    private void PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        _ = LoadAppointments();
    }

    private void NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        _ = LoadAppointments();
    }

    private async Task CreateAppointment()
    {
        formError = null;
        if (newAppointment.PatientId == 0)
        {
            formError = "Please select a patient.";
            return;
        }
        // Check for conflicts
        var end = newAppointment.ScheduledAt.AddMinutes(newAppointment.DurationMinutes);
        var conflict = await Db.Appointments.AnyAsync(a =>
            a.Status == AppointmentStatus.Scheduled &&
            a.ScheduledAt < end &&
            a.ScheduledAt.AddMinutes(a.DurationMinutes) > newAppointment.ScheduledAt);
        if (conflict)
        {
            formError = "Time slot conflicts with an existing appointment.";
            return;
        }

        newAppointment.CreatedAt = DateTime.UtcNow;
        Db.Appointments.Add(newAppointment);
        await Db.SaveChangesAsync();
        newAppointment = new() { DurationMinutes = 30 };
        showForm = false;
        await LoadAppointments();
    }

    private void StartReschedule(Appointment apt)
    {
        rescheduleTarget = apt;
        rescheduleDate = apt.ScheduledAt;
    }

    private async Task ConfirmReschedule()
    {
        if (rescheduleTarget != null)
        {
            rescheduleTarget.ScheduledAt = rescheduleDate;
            await Db.SaveChangesAsync();
            rescheduleTarget = null;
            await LoadAppointments();
        }
    }

    private async Task CancelAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }
}

