@code {
    private int patientCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<Appointment> upcomingAppointments = new();
    private List<Patient> recentPatients = new();

    protected override async Task OnInitializedAsync()
    {
        patientCount = await Db.Patients.CountAsync();
        var today = DateTime.UtcNow.Date;
        todayAppointments = await Db.Appointments
            .CountAsync(a => a.ScheduledAt.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await Db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Unpaid || i.Status == InvoiceStatus.PartiallyPaid);
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.ScheduledAt >= DateTime.UtcNow && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.ScheduledAt)
            .Take(5)
            .ToListAsync();
        recentPatients = await Db.Patients
            .OrderByDescending(p => p.CreatedAt)
            .Take(5)
            .ToListAsync();
    }
}

