@code {
    private DateOnly weekStart = DateOnly.FromDateTime(DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday));
    private List<Appointment> appointments = new();
    private List<Patient> patients = new();
    private Appointment newAppointment = new() { DurationMinutes = 30 };
    private bool showForm;
    private string? formError;
    private Appointment? rescheduleTarget;
    private DateTime rescheduleDate;

    protected override async Task OnInitializedAsync()
    {
        patients = await Db.Patients.OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var start = weekStart.ToDateTime(TimeOnly.MinValue);
        var end = start.AddDays(7);
        appointments = await Db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.ScheduledAt >= start && a.ScheduledAt < end)
            .ToListAsync();
    }

    private void PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        _ = LoadAppointments();
    }

    private void NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        _ = LoadAppointments();
    }

    private async Task CreateAppointment()
    {
        formError = null;
        if (newAppointment.PatientId == 0)
        {
            formError = "Please select a patient.";
            return;
        }
        // Check for conflicts
        var end = newAppointment.ScheduledAt.AddMinutes(newAppointment.DurationMinutes);
        var conflict = await Db.Appointments.AnyAsync(a =>
            a.Status == AppointmentStatus.Scheduled &&
            a.ScheduledAt < end &&
            a.ScheduledAt.AddMinutes(a.DurationMinutes) > newAppointment.ScheduledAt);
        if (conflict)
        {
            formError = "Time slot conflicts with an existing appointment.";
            return;
        }

        newAppointment.CreatedAt = DateTime.UtcNow;
        Db.Appointments.Add(newAppointment);
        await Db.SaveChangesAsync();
        newAppointment = new() { DurationMinutes = 30 };
        showForm = false;
        await LoadAppointments();
    }

    private void StartReschedule(Appointment apt)
    {
        rescheduleTarget = apt;
        rescheduleDate = apt.ScheduledAt;
    }

    private async Task ConfirmReschedule()
    {
        if (rescheduleTarget != null)
        {
            rescheduleTarget.ScheduledAt = rescheduleDate;
            await Db.SaveChangesAsync();
            rescheduleTarget = null;
            await LoadAppointments();
        }
    }

    private async Task CancelAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }
}

@page "/billing"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject ApplicationDbContext Db

<PageTitle>Billing — VetClinic</PageTitle>

<h1>Billing</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadInvoices">
            <option value="">All Invoices</option>
            <option value="Unpaid">Unpaid</option>
            <option value="PartiallyPaid">Partially Paid</option>
            <option value="Paid">Paid</option>
        </select>
    </div>
    <div class="col-md-8 text-end">
        <button class="btn btn-primary" @onclick="() => showInvoiceForm = !showInvoiceForm">
            @(showInvoiceForm ? "Cancel" : "Generate Invoice")
        </button>
    </div>
</div>

@if (showInvoiceForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Generate Invoice</h5>
            <EditForm Model="newInvoice" OnValidSubmit="CreateInvoice" FormName="newInvoice">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="newInvoice.PatientId">
                            <option value="0">-- Select Patient --</option>
                            @foreach (var p in patients)
                            {
                                <option value="@p.Id">@p.Name (@p.OwnerName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Total Amount ($)</label>
                        <InputNumber class="form-control" @bind-Value="newInvoice.TotalAmount" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="newInvoice.Description" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Create Invoice</button>
                @if (invoiceError != null)
                {
                    <span class="text-danger ms-2">@invoiceError</span>
                }
            </EditForm>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>#</th>
            <th>Patient</th>
            <th>Description</th>
            <th>Amount</th>
            <th>Paid</th>
            <th>Status</th>
            <th>Issued</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            var paid = inv.Payments.Sum(p => p.Amount);
            var statusBadge = inv.Status switch
            {
                InvoiceStatus.Paid => "bg-success",
                InvoiceStatus.PartiallyPaid => "bg-warning text-dark",
                _ => "bg-danger"
            };
            <tr>
                <td>@inv.Id</td>
                <td>@inv.Patient.Name</td>
                <td>@inv.Description</td>
                <td>$@inv.TotalAmount.ToString("F2")</td>
                <td>$@paid.ToString("F2")</td>
                <td><span class="badge @statusBadge">@inv.Status</span></td>
                <td>@inv.IssuedAt.ToString("d")</td>
                <td>
                    @if (inv.Status != InvoiceStatus.Paid)
                    {
                        <button class="btn btn-sm btn-outline-success" @onclick="() => StartPayment(inv)">Pay</button>
                    }
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ToggleHistory(inv.Id)">History</button>
                </td>
            </tr>
            @if (showHistoryFor == inv.Id)
            {
                <tr>
                    <td colspan="8">
                        <div class="p-2 bg-light">
                            <strong>Payment History</strong>
                            @if (inv.Payments.Any())
                            {
                                <table class="table table-sm mt-2">
                                    <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Notes</th></tr></thead>
                                    <tbody>
                                        @foreach (var pay in inv.Payments.OrderByDescending(p => p.PaidAt))
                                        {
                                            <tr>
                                                <td>@pay.PaidAt.ToString("g")</td>
                                                <td>$@pay.Amount.ToString("F2")</td>
                                                <td>@pay.Method</td>
                                                <td>@pay.Notes</td>
                                            </tr>
                                        }
                                    </tbody>
                                </table>
                            }
                            else
                            {
                                <p class="text-muted mt-2 mb-0">No payments recorded.</p>
                            }
                        </div>
                    </td>
                </tr>
            }
        }
    </tbody>
</table>

@if (!invoices.Any())
{
    <p class="text-muted">No invoices found.</p>
}

@if (paymentTarget != null)
{
    <div class="card mt-4 border-success">
        <div class="card-body">
            <h5 class="card-title">Process Payment — Invoice #@paymentTarget.Id (@paymentTarget.Patient.Name)</h5>
            <p>Outstanding: $@((paymentTarget.TotalAmount - paymentTarget.Payments.Sum(p => p.Amount)).ToString("F2"))</p>
            <EditForm Model="newPayment" OnValidSubmit="ProcessPayment" FormName="processPayment">
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Amount ($)</label>
                        <InputNumber class="form-control" @bind-Value="newPayment.Amount" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Method</label>
                        <InputSelect class="form-select" @bind-Value="newPayment.Method">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="newPayment.Notes" />
                    </div>
                    <div class="col-md-2 d-flex align-items-end mb-2">
                        <button type="submit" class="btn btn-success me-2">Pay</button>
                        <button type="button" class="btn btn-secondary" @onclick="() => paymentTarget = null">Cancel</button>
                    </div>
                </div>
                @if (paymentError != null)
                {
                    <span class="text-danger">@paymentError</span>
                }
            </EditForm>
        </div>
    </div>
}

@code {
    private List<Invoice> invoices = new();
    private List<Patient> patients = new();
    private string statusFilter = "";
    private bool showInvoiceForm;
    private Invoice newInvoice = new();
    private string? invoiceError;
    private Invoice? paymentTarget;
    private Payment newPayment = new();
    private string? paymentError;
    private int? showHistoryFor;

    protected override async Task OnInitializedAsync()
    {
        patients = await Db.Patients.OrderBy(p => p.Name).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        var query = Db.Invoices
            .Include(i => i.Patient)
            .Include(i => i.Payments)
            .AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<InvoiceStatus>(statusFilter, out var status))
        {
            query = query.Where(i => i.Status == status);
        }

        invoices = await query.OrderByDescending(i => i.IssuedAt).ToListAsync();
    }

    private async Task CreateInvoice()
    {
        invoiceError = null;
        if (newInvoice.PatientId == 0)
        {
            invoiceError = "Please select a patient.";
            return;
        }
        if (newInvoice.TotalAmount <= 0)
        {
            invoiceError = "Amount must be greater than zero.";
            return;
        }
        newInvoice.IssuedAt = DateTime.UtcNow;
        newInvoice.Status = InvoiceStatus.Unpaid;
        Db.Invoices.Add(newInvoice);
        await Db.SaveChangesAsync();
        newInvoice = new();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private void StartPayment(Invoice inv)
    {
        paymentTarget = inv;
        newPayment = new() { InvoiceId = inv.Id };
        paymentError = null;
    }

    private async Task ProcessPayment()
    {
        paymentError = null;
        if (newPayment.Amount <= 0)
        {
            paymentError = "Amount must be greater than zero.";
            return;
        }
        var outstanding = paymentTarget!.TotalAmount - paymentTarget.Payments.Sum(p => p.Amount);
        if (newPayment.Amount > outstanding)
        {
            paymentError = $"Amount exceeds outstanding balance of ${outstanding:F2}.";
            return;
        }

        newPayment.PaidAt = DateTime.UtcNow;
        newPayment.InvoiceId = paymentTarget.Id;
        Db.Payments.Add(newPayment);

        var totalPaid = paymentTarget.Payments.Sum(p => p.Amount) + newPayment.Amount;
        paymentTarget.Status = totalPaid >= paymentTarget.TotalAmount
            ? InvoiceStatus.Paid
            : InvoiceStatus.PartiallyPaid;

        await Db.SaveChangesAsync();
        paymentTarget = null;
        newPayment = new();
        await LoadInvoices();
    }

    private void ToggleHistory(int invoiceId)
    {
        showHistoryFor = showHistoryFor == invoiceId ? null : invoiceId;
    }
}

